module RefModule (
    input wire D,
    input wire WE,
    output reg Q
);
  wire _tap_D = D & {1{1'b1}};

    always @(WE or D) begin
        if (WE) begin
            Q <= D; // Store data when WE is high
        end
        // If WE is low, maintain the previous value of Q
    end
endmodule
